package com.wjx871.population.household;
import java.time.*; import java.util.List;
record HouseholdView(Long householdId,String householdNo,Long headPersonId,String headPersonName,String address,String regionCode,String householdType,LocalDate establishDate,String status,Integer version,Long activeMemberCount,List<HouseholdMemberView> members){static HouseholdView from(Household h,List<HouseholdMemberView> m,String address){return new HouseholdView(h.getHouseholdId(),h.getHouseholdNo(),h.getHeadPersonId(),h.getHeadPersonName(),address,h.getRegionCode(),h.getHouseholdType(),h.getEstablishDate(),h.getStatus(),h.getVersion(),h.getActiveMemberCount(),m);}}
record HouseholdMemberView(Long memberId,Long householdId,Long personId,String personName,String idCard,String phone,String relationship,LocalDate joinDate,LocalDate leaveDate,String status,Integer version){static HouseholdMemberView from(HouseholdMember m,String id,String phone){return new HouseholdMemberView(m.getMemberId(),m.getHouseholdId(),m.getPersonId(),m.getPersonName(),id,phone,m.getRelationship(),m.getJoinDate(),m.getLeaveDate(),m.getStatus(),m.getVersion());}}
